import{_ as a,o as s,c as i,ak as n}from"./chunks/framework.DwHlt8HN.js";const k=JSON.parse('{"title":"微服务统一认证方案：Session 共享 vs Token 方案","description":"","frontmatter":{},"headers":[],"relativePath":"distributed/scenario/unified-auth/index.md","filePath":"distributed/scenario/unified-auth/index.md","lastUpdated":1774318215000}'),t={name:"distributed/scenario/unified-auth/index.md"};function o(r,e,d,l,h,p){return s(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="微服务统一认证方案-session-共享-vs-token-方案" tabindex="-1">微服务统一认证方案：Session 共享 vs Token 方案 <a class="header-anchor" href="#微服务统一认证方案-session-共享-vs-token-方案" aria-label="Permalink to “微服务统一认证方案：Session 共享 vs Token 方案”">​</a></h1><p>你有没有想过这样一个问题：用户在你的电商网站登录了一次，为什么访问商品详情、购物车、订单列表这些不同的微服务，都能保持登录状态？</p><p>这不是因为每个微服务都「认识」这个用户，而是有一个统一的机制，让每个服务都知道「当前请求是谁发来的」。</p><p>这就是微服务认证要解决的核心问题。</p><h2 id="问题的本质" tabindex="-1">问题的本质 <a class="header-anchor" href="#问题的本质" aria-label="Permalink to “问题的本质”">​</a></h2><p>在单体架构下，用户登录后信息存在应用服务器的 Session 中，后续请求带着 Cookie，服务端从 Session 取用户信息，一切都很自然。</p><p>但微服务架构下，一个请求可能经过网关、商品服务、订单服务、支付服务等多个节点。每个节点都是独立的进程、独立的应用服务器——<strong>Session 存在哪个节点？其他节点怎么知道用户已经登录了？</strong></p><p>这就是分布式认证的起点。</p><h2 id="方案一-session-共享" tabindex="-1">方案一：Session 共享 <a class="header-anchor" href="#方案一-session-共享" aria-label="Permalink to “方案一：Session 共享”">​</a></h2><p>最直接的想法是：既然 Session 不能存在单机，那就把它存到一个所有服务都能访问的地方。</p><p><strong>Redis</strong>，成了天然的选择。</p><h3 id="核心原理" tabindex="-1">核心原理 <a class="header-anchor" href="#核心原理" aria-label="Permalink to “核心原理”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>用户登录 → 生成 Session → 存入 Redis</span></span>
<span class="line"><span>请求到达 → 各服务从 Redis 读取 Session → 获取用户信息</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>所有微服务都连接同一个 Redis，Session 数据天然共享。</p><h3 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to “优点”">​</a></h3><p>与单体应用架构一致，对现有代码改动小。Session 的生命周期管理（过期、销毁）由 Redis 处理，逻辑清晰。用户主动登出时，只需删除 Redis 中的 Session 即可。</p><h3 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to “缺点”">​</a></h3><p><strong>跨域问题</strong>：Session 依赖 Cookie，Cookie 有域限制。如果你有 <code>api.example.com</code> 和 <code>web.example.com</code> 两个域名，需要设置 Cookie 的 Domain 为 <code>.example.com</code>，这对子域名有限制。</p><p><strong>序列化开销</strong>：Session 数据需要序列化和反序列化。Java 默认的序列化效率低，换成 JSON 后又要处理类型丢失问题。</p><p><strong>Cookie 大小限制</strong>：Cookie 本身有 4KB 限制。如果 Session 数据过大，存不进去。</p><p><strong>性能瓶颈</strong>：每次请求都要访问 Redis，虽然是毫秒级，但在高并发下仍可能成为瓶颈。</p><h3 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to “适用场景”">​</a></h3><p>企业内部系统，微服务数量不多，团队对 Session 模式更熟悉。</p><h2 id="方案二-token-方案" tabindex="-1">方案二：Token 方案 <a class="header-anchor" href="#方案二-token-方案" aria-label="Permalink to “方案二：Token 方案”">​</a></h2><p>Token 方案的核心思路完全不同：<strong>不要服务端存储，让客户端带着「身份证明」来访问。</strong></p><h3 id="jwt-的结构" tabindex="-1">JWT 的结构 <a class="header-anchor" href="#jwt-的结构" aria-label="Permalink to “JWT 的结构”">​</a></h3><p>最常用的是 JWT（JSON Web Token），它由三部分组成：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Header.Payload.Signature</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><strong>Header</strong>：存储算法和类型，<code>{&quot;alg&quot;: &quot;HS256&quot;, &quot;typ&quot;: &quot;JWT&quot;}</code></li><li><strong>Payload</strong>：存储用户信息、过期时间、签发者，<code>{&quot;userId&quot;: 123, &quot;exp&quot;: 1699999999}</code></li><li><strong>Signature</strong>：用密钥对 Header 和 Payload 签名，防止篡改</li></ul><p>三部分分别 Base64 编码，用 <code>.</code> 连接。</p><h3 id="token-的工作流程" tabindex="-1">Token 的工作流程 <a class="header-anchor" href="#token-的工作流程" aria-label="Permalink to “Token 的工作流程”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>用户登录 → 服务端生成 Token（签名）→ 返回给客户端</span></span>
<span class="line"><span>请求到达 → 验证 Token 签名 → 解析用户信息 → 处理请求</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Token 存在客户端，每次请求放在 Header 里（通常是 <code>Authorization: Bearer &lt;token&gt;</code>）。</p><h3 id="优点-1" tabindex="-1">优点 <a class="header-anchor" href="#优点-1" aria-label="Permalink to “优点”">​</a></h3><p><strong>无状态</strong>：服务端不存储 Token，任意节点都能验证。水平扩展友好，新增节点无需共享任何状态。</p><p><strong>支持跨域</strong>：Token 放在 Header 里，不依赖 Cookie，自然支持跨域访问。</p><p><strong>性能好</strong>：验证 Token 只是签名运算，不需要网络访问。</p><h3 id="缺点-1" tabindex="-1">缺点 <a class="header-anchor" href="#缺点-1" aria-label="Permalink to “缺点”">​</a></h3><p><strong>撤销困难</strong>：Token 在过期前一直有效。如果用户被禁用，传统方案无法让 Token 立即失效。</p><p><strong>Payload 不能存敏感信息</strong>：Token 是 Base64 编码的，可被解码。虽然有签名防篡改，但内容是明文的，敏感信息不能放里面。</p><p><strong>Token 体积</strong>：每次请求都要携带，比 Cookie 多一些网络开销。</p><h3 id="适用场景-1" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景-1" aria-label="Permalink to “适用场景”">​</a></h3><p>互联网应用，需要支持跨域、API 开放、水平扩展。</p><h2 id="两种方案的对比" tabindex="-1">两种方案的对比 <a class="header-anchor" href="#两种方案的对比" aria-label="Permalink to “两种方案的对比”">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Session 共享</th><th>Token</th></tr></thead><tbody><tr><td>存储位置</td><td>Redis</td><td>客户端</td></tr><tr><td>状态</td><td>有状态</td><td>无状态</td></tr><tr><td>扩展性</td><td>需要 Redis 支持</td><td>天生可扩展</td></tr><tr><td>跨域支持</td><td>需要特殊处理</td><td>原生支持</td></tr><tr><td>撤销能力</td><td>立即生效</td><td>需要额外机制</td></tr><tr><td>性能</td><td>每次请求一次 Redis</td><td>纯本地计算</td></tr><tr><td>适用场景</td><td>企业内网</td><td>互联网应用</td></tr></tbody></table><h2 id="实际选型建议" tabindex="-1">实际选型建议 <a class="header-anchor" href="#实际选型建议" aria-label="Permalink to “实际选型建议”">​</a></h2><p><strong>选 Session + Redis</strong>：如果你的系统是传统企业应用，微服务数量不多，团队对 Session 模式更熟悉。Spring Session + Redis 的组合已经很成熟，能覆盖大部分场景。</p><p><strong>选 Token</strong>：如果你是互联网应用，需要 API 开放、跨域支持、移动端登录，或者微服务数量很多、扩展频繁。JWT 是目前的主流选择。</p><h2 id="一个常见的误区" tabindex="-1">一个常见的误区 <a class="header-anchor" href="#一个常见的误区" aria-label="Permalink to “一个常见的误区”">​</a></h2><p>很多人觉得 Token 比 Session 「更安全」，这是不对的。</p><p>两者只是存储位置不同，安全性取决于实现细节。Token 如果泄露，同样可以被冒用。Session 如果用 HTTPS + HttpOnly + SameSite，同样很安全。</p><p>真正需要关注的，是 Token 的有效期设置、敏感信息的保护、以及传输过程中的 HTTPS 加密。</p><h2 id="面试追问方向" tabindex="-1">面试追问方向 <a class="header-anchor" href="#面试追问方向" aria-label="Permalink to “面试追问方向”">​</a></h2><ul><li>Token 泄露了怎么办？（答：短期 Token + 黑名单机制）</li><li>如何实现 Token 的主动失效？（答：结合 Redis 黑名单或 Token 版本号）</li><li>Session 和 Token 能否混合使用？（答：可以，Token 做认证，Session 做会话管理）</li></ul><p>这些追问的答案，我会在后续的 <a href="/distributed/scenario/unified-auth/jwt-stateless">JWT 无状态方案</a> 和 <a href="/distributed/scenario/unified-auth/distributed-session">分布式 Session</a> 中详细展开。</p><p>微服务认证没有银弹，根据业务场景选对方案，比追新更重要。</p>`,56)])])}const b=a(t,[["render",o]]);export{k as __pageData,b as default};
